section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-observability-stack-blueprint-output",
  "required": [
    "vendor",
    "otel_spans_enabled",
    "cost_ledger_schema",
    "judge_sample_pct",
    "drift_alert_threshold",
    "forbidden_seen"
  ],
  "properties": {
    "vendor": {
      "description": "Chosen vendor."
    },
    "otel_spans_enabled": {
      "description": "OTel emission live."
    },
    "cost_ledger_schema": {
      "description": "Fields: provider, model, input_t, output_t, usd."
    },
    "judge_sample_pct": {
      "description": "1-10."
    },
    "drift_alert_threshold": {
      "description": "Judge-score delta over 7d."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
